                    sb.AppendLine($"<td>{alert.Principle}</td>");
                    sb.AppendLine($"<td>{alert.ClassName}</td>");
                    sb.AppendLine($"<td>{alert.Namespace}</td>");
                    sb.AppendLine($"<td>{alert.Reason}</td>");
                    sb.AppendLine("</tr>");
                }
                sb.AppendLine("</table>");
            }

